def main():
    n, m = map(int, input().split())
    a = list(map(int, input().split()))
    if m == 1:
        print('YES')
        return
    if n == 1 and a[0] % m == 0:
        print('YES')
        return
    b = [0] * m
    b[a[0] % m] = 1
    for i in range(1, n):
        b[a[i] % m] += 1
    if b[0] > 0:
        print('YES')
        return
    for i in range(1, m):
        if b[i] > 1:
            print('YES')
            return
    print('NO')


